"""
Parameterized generator for GH922_pandas_64882.

Source PR:    https://github.com/pandas-dev/pandas/pull/64882
Source Issue: N/A

Seed varies: renames 'again' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH922_pandas_64882'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH922_pandas_64882'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('again', 'again' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH922_pandas_64882',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pandas-dev/pandas',
                "pr_number": 64882,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pandas-dev/pandas/pull/64882",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'doc/source/whatsnew/v3.0.2.rst': '.. _whatsnew_302:\n\nWhat\'s new in 3.0.2 (March XX, 2026)\n---------------------------------------\n\nThese are the changes in pandas 3.0.2. See :ref:`release` for a full changelog\nincluding other versions of pandas.\n\n{{ header }}\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.enhancements:\n\nEnhancements\n~~~~~~~~~~~~\n- Added support for :func:`pd.col` expressions in :meth:`Series.case_when` (:issue:`64070`).\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.regressions:\n\nFixed regressions\n~~~~~~~~~~~~~~~~~\n- Fixed a regression in :func:`json_normalize` that caused top-level missing entries to raise a ``TypeError``. Missing entries are once again interpreted as empty records (:issue:`64188`)\n- Fixed regression in :meth:`HDFStore.select` where the ``where`` clause on a datetime index silently returned empty results when the index had non-nanosecond resolution (:issue:`64310`)\n- Fixed regression in :meth:`Series.interpolate` where ``limit_direction="both"`` with ``limit`` greater than the Series length raised ``ValueError`` (:issue:`64322`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.bug_fixes:\n\nBug fixes\n^^^^^^^^^\n- :func:`col` and expressions derived from it failed with power (``**``) and matrix multiplication (``@``) operators (:issue:`64267`)\n- Assigning :attr:`pd.NA` to a string column could trigger a PyArrow error and corrupt data (:issue:`64320`)\n- Bug when using :func:`col` with Python functions :func:`bool`, :func:`iter`, :func:`copy`, and :func:`deepcopy` either failed or produced incorrect results; these now all raise a ``TypeError`` (:issue:`64267`)\n- Fixed bug in the :meth:`~Series.sum` method with python-backed string dtype returning incorrect value for an empty Series and ignoring the ``min_count`` argument (:issue:`64683`)\n- Fixed bug where :meth:`DataFrame.div` ignored the ``axis`` argument when used with ``level`` for MultiIndex columns (:issue:`64428`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.contributors:\n\nContributors\n~~~~~~~~~~~~\n\n.. contributors:: v3.0.1..v3.0.2|HEAD\n',
            'pandas/core/indexes/range.py': 'from __future__ import annotations\n\nfrom collections.abc import (\n    Callable,\n    Hashable,\n    Iterator,\n)\nfrom datetime import timedelta\nimport operator\nfrom sys import getsizeof\nfrom typing import (\n    TYPE_CHECKING,\n    Any,\n    Literal,\n    Self,\n    cast,\n    overload,\n)\n\nimport numpy as np\n\nfrom pandas._libs import (\n    index as libindex,\n    lib,\n)\nfrom pandas._libs.lib import no_default\nfrom pandas.compat.numpy import function as nv\nfrom pandas.util._decorators import (\n    cache_readonly,\n    set_module,\n)\n\nfrom pandas.core.dtypes.base import ExtensionDtype\nfrom pandas.core.dtypes.common import (\n    ensure_platform_int,\n    ensure_python_int,\n    is_float,\n    is_integer,\n    is_scalar,\n    is_signed_integer_dtype,\n)\nfrom pandas.core.dtypes.generic import ABCTimedeltaIndex\n\nfrom pandas.core import ops\nimport pandas.core.common as com\nfrom pandas.core.construction import extract_array\nfrom pandas.core.indexers import check_array_indexer\nimport pandas.core.indexes.base as ibase\nfrom pandas.core.indexes.base import (\n    Index,\n    maybe_extract_name,\n)\nfrom pandas.core.ops.common import unpack_zerodim_and_defer\n\nif TYPE_CHECKING:\n    from pandas._typing import (\n        Axis,\n        Dtype,\n        JoinHow,\n        NaPosition,\n        NumpySorter,\n        npt,\n    )\n\n    from pandas import Series\n\n_empty_range = range(0)\n_dtype_int64 = np.dtype(np.int64)\n\n\ndef min_fitting_element(start: int, step: int, lower_limit: int) -> int:\n    """Returns the smallest element greater than or equal to the limit"""\n    no_steps = -(-(lower_limit - start) // abs(step))\n    return start + abs(step) * no_steps\n\n\n@set_module("pandas")\nclass RangeIndex(Index):\n    """\n    Immutable Index implementing a monotonic integer range.\n\n    RangeIndex is a memory-saving special case of an Index limited to representing\n    monotonic ranges with a 64-bit dtype. Using RangeIndex may in some instances\n    improve computing speed.\n\n    This is the default index type used\n    by DataFrame and Series when no explicit index is provided by the user.\n\n    Parameters\n    ----------\n    start : int, range, or other RangeIndex instance, default None\n        If int and "stop" is not given, interpreted as "stop" instead.\n    stop : int, default None\n        The end value of the range (exclusive).\n    step : int, default None\n        The step size of the range.\n    dtype : np.int64, default None\n        Unused, accepted for homogeneity with other index types.\n    copy : bool, default False\n        Unused, accepted for homogeneity with other index types.\n    name : object, optional\n        Name to be stored in the index.\n\n    Attributes\n    ----------\n    start\n    stop\n    step\n\n    Methods\n    -------\n    from_range\n\n    See Also\n    --------\n    Index : The base pandas Index type.\n\n    Examples\n    --------\n    >>> list(pd.RangeIndex(5))\n    [0, 1, 2, 3, 4]\n\n    >>> list(pd.RangeIndex(-2, 4))\n    [-2, -1, 0, 1, 2, 3]\n\n    >>> list(pd.RangeIndex(0, 10, 2))\n    [0, 2, 4, 6, 8]\n\n    >>> list(pd.RangeIndex(2, -10, -3))\n    [2, -1, -4, -7]\n\n    >>> list(pd.RangeIndex(0))\n    []\n\n    >>> list(pd.RangeIndex(1, 0))\n    []\n    """\n\n    _typ = "rangeindex"\n    _dtype_validation_metadata = (is_signed_integer_dtype, "signed integer")\n    _range: range\n    _values: np.ndarray\n\n    @property\n    def _engine_type(self) -> type[libindex.Int64Engine]:\n        return libindex.Int64Engine\n\n    # --------------------------------------------------------------------\n    # Constructors\n\n    def __new__(\n        cls,\n        start=None,\n        stop=None,\n        step=None,\n        dtype: Dtype | None = None,\n        copy: bool = False,\n        name: Hashable | None = None,\n    ) -> Self:\n        cls._validate_dtype(dtype)\n        name = maybe_extract_name(name, start, cls)\n\n        # RangeIndex\n        if isinstance(start, cls):\n            return start.copy(name=name)\n        elif isinstance(start, range):\n            return cls._simple_new(start, name=name)\n\n        # validate the arguments\n        if com.all_none(start, stop, step):\n            raise TypeError("RangeIndex(...) must be called with integers")\n\n        start = ensure_python_int(start) if start is not None else 0\n\n        if stop is None:\n            start, stop = 0, start\n        else:\n            stop = ensure_python_int(stop)\n\n        step = ensure_python_int(step) if step is not None else 1\n        if step == 0:\n            raise ValueError("Step must not be zero")\n\n        rng = range(start, stop, step)\n        return cls._simple_new(rng, name=name)\n\n    @classmethod\n    def from_range(cls, data: range, name=None, dtype: Dtype | None = None) -> Self:\n        """\n        Create :class:`pandas.RangeIndex` from a ``range`` object.\n\n        This method provides a way to create a :class:`pandas.RangeIndex` directly\n        from a Python ``range`` object. The resulting :class:`RangeIndex` will have\n        the same start, stop, and step values as the input ``range`` object.\n        It is particularly useful for constructing indices in an efficient and\n        memory-friendly manner.\n\n        Parameters\n        ----------\n        data : range\n            The range object to be converted into a RangeIndex.\n        name : str, default None\n            Name to be stored in the index.\n        dtype : Dtype or None\n            Data type for the RangeIndex. If None, the default integer type will\n            be used.\n\n        Returns\n        -------\n        RangeIndex\n\n        See Also\n        --------\n        RangeIndex : Immutable Index implementing a monotonic integer range.\n        Index : Immutable sequence used for indexing and alignment.\n\n        Examples\n        --------\n        >>> pd.RangeIndex.from_range(range(5))\n        RangeIndex(start=0, stop=5, step=1)\n\n        >>> pd.RangeIndex.from_range(range(2, -10, -3))\n        RangeIndex(start=2, stop=-10, step=-3)\n        """\n        if not isinstance(data, range):\n            raise TypeError(\n                f"{cls.__name__}(...) must be called with object coercible to a "\n                f"range, {data!r} was passed"\n            )\n        cls._validate_dtype(dtype)\n        return cls._simple_new(data, name=name)\n\n    #  error: Argument 1 of "_simple_new" is incompatible with supertype "Index";\n    #  supertype defines the argument type as\n    #  "Union[ExtensionArray, ndarray[Any, Any]]"  [override]\n    @classmethod\n    def _simple_new(  # type: ignore[override]\n        cls, values: range, name: Hashable | None = None\n    ) -> Self:\n        result = object.__new__(cls)\n\n        assert isinstance(values, range)\n\n        result._range = values\n        result._name = name\n        result._cache = {}\n        result._reset_identity()\n        result._references = None\n        return result\n\n    @classmethod\n    def _validate_dtype(cls, dtype: Dtype | None) -> None:\n        if dtype is None:\n            return\n\n        validation_func, expected = cls._dtype_validation_metadata\n        if not validation_func(dtype):\n            raise ValueError(\n                f"Incorrect `dtype` passed: expected {expected}, received {dtype}"\n            )\n\n    # --------------------------------------------------------------------\n\n    # error: Return type "Type[Index]" of "_constructor" incompatible with return\n    # type "Type[RangeIndex]" in supertype "Index"\n    @cache_readonly\n    def _constructor(self) -> type[Index]:  # type: ignore[override]\n        """return the class to use for construction"""\n        return Index\n\n    # error: Signature of "_data" incompatible with supertype "Index"\n    @cache_readonly\n    def _data(self) -> np.ndarray:  # type: ignore[override]\n        """\n        An int array that for performance reasons is created only when needed.\n\n        The constructed array is saved in ``_cache``.\n        """\n        return np.arange(self.start, self.stop, self.step, dtype=np.int64)\n\n    def _get_data_as_items(self) -> list[tuple[str, int]]:\n        """return a list of tuples of start, stop, step"""\n        rng = self._range\n        return [("start", rng.start), ("stop", rng.stop), ("step", rng.step)]\n\n    def __reduce__(self):\n        d = {"name": self._name}\n        d.update(dict(self._get_data_as_items()))\n        return ibase._new_Index, (type(self), d), None\n\n    # --------------------------------------------------------------------\n    # Rendering Methods\n\n    def _format_attrs(self):\n        """\n        Return a list of tuples of the (attr, formatted_value)\n        """\n        attrs = cast("list[tuple[str, str | int]]", self._get_data_as_items())\n        if self._name is not None:\n            attrs.append(("name", ibase.default_pprint(self._name)))\n        return attrs\n\n    def _format_with_header(self, *, header: list[str], na_rep: str) -> list[str]:\n        # Equivalent to Index implementation, but faster\n        if not len(self._range):\n            return header\n        first_val_str = str(self._range[0])\n        last_val_str = str(self._range[-1])\n        max_length = max(len(first_val_str), len(last_val_str))\n\n        return header + [f"{x:<{max_length}}" for x in self._range]\n\n    # --------------------------------------------------------------------\n\n    @property\n    def start(self) -> int:\n        """\n        The value of the `start` parameter (``0`` if this was not supplied).\n\n        This property returns the starting value of the `RangeIndex`. If the `start`\n        value is not explicitly provided during the creation of the `RangeIndex`,\n        it defaults to 0.\n\n        See Also\n        --------\n        RangeIndex : Immutable index implementing a range-based index.\n        RangeIndex.stop : Returns the stop value of the `RangeIndex`.\n        RangeIndex.step : Returns the step value of the `RangeIndex`.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(5)\n        >>> idx.start\n        0\n\n        >>> idx = pd.RangeIndex(2, -10, -3)\n        >>> idx.start\n        2\n        """\n        # GH 25710\n        return self._range.start\n\n    @property\n    def stop(self) -> int:\n        """\n        The value of the `stop` parameter.\n\n        This property returns the `stop` value of the RangeIndex, which defines the\n        upper (or lower, in case of negative steps) bound of the index range. The\n        `stop` value is exclusive, meaning the RangeIndex includes values up to but\n        not including this value.\n\n        See Also\n        --------\n        RangeIndex : Immutable index representing a range of integers.\n        RangeIndex.start : The start value of the RangeIndex.\n        RangeIndex.step : The step size between elements in the RangeIndex.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(5)\n        >>> idx.stop\n        5\n\n        >>> idx = pd.RangeIndex(2, -10, -3)\n        >>> idx.stop\n        -10\n        """\n        return self._range.stop\n\n    @property\n    def step(self) -> int:\n        """\n        The value of the `step` parameter (``1`` if this was not supplied).\n\n        The ``step`` parameter determines the increment (or decrement in the case\n        of negative values) between consecutive elements in the ``RangeIndex``.\n\n        See Also\n        --------\n        RangeIndex : Immutable index implementing a range-based index.\n        RangeIndex.stop : Returns the stop value of the RangeIndex.\n        RangeIndex.start : Returns the start value of the RangeIndex.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(5)\n        >>> idx.step\n        1\n\n        >>> idx = pd.RangeIndex(2, -10, -3)\n        >>> idx.step\n        -3\n\n        Even if :class:`pandas.RangeIndex` is empty, ``step`` is still ``1`` if\n        not supplied.\n\n        >>> idx = pd.RangeIndex(1, 0)\n        >>> idx.step\n        1\n        """\n        # GH 25710\n        return self._range.step\n\n    @cache_readonly\n    def nbytes(self) -> int:\n        """\n        Return the number of bytes in the underlying data.\n        """\n        rng = self._range\n        return getsizeof(rng) + sum(\n            getsizeof(getattr(rng, attr_name))\n            for attr_name in ["start", "stop", "step"]\n        )\n\n    def memory_usage(self, deep: bool = False) -> int:\n        """\n        Memory usage of my values\n\n        Parameters\n        ----------\n        deep : bool\n            Introspect the data deeply, interrogate\n            `object` dtypes for system-level memory consumption\n\n        Returns\n        -------\n        bytes used\n\n        Notes\n        -----\n        Memory usage does not include memory consumed by elements that\n        are not components of the array if deep=False\n\n        See Also\n        --------\n        numpy.ndarray.nbytes\n        """\n        return self.nbytes\n\n    @property\n    def dtype(self) -> np.dtype:\n        return _dtype_int64\n\n    @property\n    def is_unique(self) -> bool:\n        """return if the index has unique values"""\n        return True\n\n    @cache_readonly\n    def is_monotonic_increasing(self) -> bool:\n        return self._range.step > 0 or len(self) <= 1\n\n    @cache_readonly\n    def is_monotonic_decreasing(self) -> bool:\n        return self._range.step < 0 or len(self) <= 1\n\n    def __contains__(self, key: Any) -> bool:\n        hash(key)\n        try:\n            key = ensure_python_int(key)\n        except (TypeError, OverflowError):\n            return False\n        return key in self._range\n\n    @property\n    def inferred_type(self) -> str:\n        return "integer"\n\n    # --------------------------------------------------------------------\n    # Indexing Methods\n\n    def get_loc(self, key) -> int:\n        """\n        Get integer location for requested label.\n\n        Parameters\n        ----------\n        key : int or float\n            Label to locate. Integer-like floats (e.g. 3.0) are accepted and\n            treated as the corresponding integer. Non-integer floats and other\n            non-integer labels are not valid and will raise KeyError or\n            InvalidIndexError.\n\n        Returns\n        -------\n        int\n            Integer location of the label within the RangeIndex.\n\n        Raises\n        ------\n        KeyError\n            If the label is not present in the RangeIndex or the label is a\n            non-integer value.\n        InvalidIndexError\n            If the label is of an invalid type for the RangeIndex.\n\n        See Also\n        --------\n        RangeIndex.get_slice_bound : Calculate slice bound that corresponds to\n            given label.\n        RangeIndex.get_indexer : Computes indexer and mask for new index given\n            the current index.\n        RangeIndex.get_non_unique : Returns indexer and masks for new index given\n            the current index.\n        RangeIndex.get_indexer_for : Returns an indexer even when non-unique.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(5)\n        >>> idx.get_loc(3)\n        3\n\n        >>> idx = pd.RangeIndex(2, 10, 2)  # values [2, 4, 6, 8]\n        >>> idx.get_loc(6)\n        2\n        """\n        if is_integer(key) or (is_float(key) and key.is_integer()):\n            new_key = int(key)\n            try:\n                return self._range.index(new_key)\n            except ValueError as err:\n                raise KeyError(key) from err\n        if isinstance(key, Hashable):\n            raise KeyError(key)\n        self._check_indexing_error(key)\n        raise KeyError(key)\n\n    def _get_indexer(\n        self,\n        target: Index,\n        method: str | None = None,\n        limit: int | None = None,\n        tolerance=None,\n    ) -> npt.NDArray[np.intp]:\n        if com.any_not_none(method, tolerance, limit):\n            return super()._get_indexer(\n                target, method=method, tolerance=tolerance, limit=limit\n            )\n\n        if self.step > 0:\n            start, stop, step = self.start, self.stop, self.step\n        else:\n            # GH 28678: work on reversed range for simplicity\n            reverse = self._range[::-1]\n            start, stop, step = reverse.start, reverse.stop, reverse.step\n\n        target_array = np.asarray(target)\n        locs = target_array - start\n        valid = (locs % step == 0) & (locs >= 0) & (target_array < stop)\n        locs[~valid] = -1\n        locs[valid] = locs[valid] / step\n\n        if step != self.step:\n            # We reversed this range: transform to original locs\n            locs[valid] = len(self) - 1 - locs[valid]\n        return ensure_platform_int(locs)\n\n    @cache_readonly\n    def _should_fallback_to_positional(self) -> bool:\n        """\n        Should an integer key be treated as positional?\n        """\n        return False\n\n    # --------------------------------------------------------------------\n\n    def tolist(self) -> list[int]:\n        return list(self._range)\n\n    def __iter__(self) -> Iterator[int]:\n        """\n        Return an iterator of the values.\n\n        Returns\n        -------\n        iterator\n            An iterator yielding ints from the RangeIndex.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(3)\n        >>> for x in idx:\n        ...     print(x)\n        0\n        1\n        2\n        """\n        yield from self._range\n\n    def _shallow_copy(self, values, name: Hashable = no_default):\n        """\n        Create a new RangeIndex with the same class as the caller, don\'t copy the\n        data, use the same object attributes with passed in attributes taking\n        precedence.\n\n        *this is an internal non-public method*\n\n        Parameters\n        ----------\n        values : the values to create the new RangeIndex, optional\n        name : Label, defaults to self.name\n        """\n        name = self._name if name is no_default else name\n\n        if values.dtype.kind == "f":\n            return Index(values, name=name, dtype=np.float64, copy=False)\n        if values.dtype.kind == "i" and values.ndim == 1:\n            # GH 46675 & 43885: If values is equally spaced, return a\n            # more memory-compact RangeIndex instead of Index with 64-bit dtype\n            if len(values) == 1:\n                start = values[0]\n                new_range = range(start, start + self.step, self.step)\n                return type(self)._simple_new(new_range, name=name)\n            maybe_range = ibase.maybe_sequence_to_range(values)\n            if isinstance(maybe_range, range):\n                return type(self)._simple_new(maybe_range, name=name)\n        return self._constructor._simple_new(values, name=name)\n\n    def _view(self) -> Self:\n        result = type(self)._simple_new(self._range, name=self._name)\n        result._cache = self._cache\n        return result\n\n    def _wrap_reindex_result(self, target, indexer, preserve_names: bool):\n        if not isinstance(target, type(self)) and target.dtype.kind == "i":\n            target = self._shallow_copy(target._values, name=target.name)\n        return super()._wrap_reindex_result(target, indexer, preserve_names)\n\n    def copy(self, name: Hashable | None = None, deep: bool = False) -> Self:\n        """\n        Make a copy of this object.\n\n        Name is set on the new object.\n\n        Parameters\n        ----------\n        name : Label, optional\n            Set name for new object.\n        deep : bool, default False\n            If True attempts to make a deep copy of the RangeIndex.\n                Else makes a shallow copy.\n\n        Returns\n        -------\n        RangeIndex\n            RangeIndex refer to new object which is a copy of this object.\n\n        See Also\n        --------\n        RangeIndex.delete: Make new RangeIndex with passed location(-s) deleted.\n        RangeIndex.drop: Make new RangeIndex with passed list of labels deleted.\n\n        Notes\n        -----\n        In most cases, there should be no functional difference from using\n        ``deep``, but if ``deep`` is passed it will attempt to deepcopy.\n\n        Examples\n        --------\n        >>> idx = pd.RangeIndex(3)\n        >>> new_idx = idx.copy()\n        >>> idx is new_idx\n        False\n        """\n        name = self._validate_names(name=name, deep=deep)[0]\n        new_index = self._rename(name=name)\n        return new_index\n\n    def _minmax(self, meth: Literal["min", "max"]) -> int | float:\n        no_steps = len(self) - 1\n        if no_steps == -1:\n            return np.nan\n        elif (meth == "min" and self.step > 0) or (meth == "max" and self.step < 0):\n            return self.start\n\n        return self.start + self.step * no_steps\n\n    def min(self, axis=None, skipna: bool = True, *args, **kwargs) -> int | float:\n        """The minimum value of the RangeIndex"""\n        nv.validate_minmax_axis(axis)\n        nv.validate_min(args, kwargs)\n        return self._minmax("min")\n\n    def max(self, axis=None, skipna: bool = True, *args, **kwargs) -> int | float:\n        """The maximum value of the RangeIndex"""\n        nv.validate_minmax_axis(axis)\n        nv.validate_max(args, kwargs)\n        return self._minmax("max")\n\n    def _argminmax(\n        self,\n        meth: Literal["min", "max"],\n        axis=None,\n        skipna: bool = True,\n    ) -> int:\n        nv.validate_minmax_axis(axis)\n        if len(self) == 0:\n            return getattr(super(), f"arg{meth}")(\n                axis=axis,\n                skipna=skipna,\n            )\n        elif meth == "min":\n            if self.step > 0:\n                return 0\n            else:\n                return len(self) - 1\n        elif meth == "max":\n            if self.step > 0:\n                return len(self) - 1\n            else:\n                return 0\n        else:\n            raise ValueError(f"{meth=} must be max or min")\n\n    def argmin(self, axis=None, skipna: bool = True, *args, **kwargs) -> int:\n        nv.validate_argmin(args, kwargs)\n        return self._argminmax("min", axis=axis, skipna=skipna)\n\n    def argmax(self, axis=None, skipna: bool = True, *args, **kwargs) -> int:\n        nv.validate_argmax(args, kwargs)\n        return self._argminmax("max", axis=axis, skipna=skipna)\n\n    def argsort(self, *args, **kwargs) -> npt.NDArray[np.intp]:\n        """\n        Returns the indices that would sort the index and its\n        underlying data.\n\n        Returns\n        -------\n        np.ndarray[np.intp]\n\n        See Also\n        --------\n        numpy.ndarray.argsort\n        """\n        ascending = kwargs.pop("ascending", True)  # EA compat\n        kwargs.pop("kind", None)  # e.g. "mergesort" is irrelevant\n        nv.validate_argsort(args, kwargs)\n\n        start, stop, step = None, None, None\n        if self._range.step > 0:\n            if ascending:\n                start = len(self)\n            else:\n                start, stop, step = len(self) - 1, -1, -1\n        elif ascending:\n            start, stop, step = len(self) - 1, -1, -1\n        else:\n            start = len(self)\n\n        return np.arange(start, stop, step, dtype=np.intp)\n\n    def factorize(\n        self,\n        sort: bool = False,\n        use_na_sentinel: bool = True,\n    ) -> tuple[npt.NDArray[np.intp], RangeIndex]:\n        if sort and self.step < 0:\n            codes = np.arange(len(self) - 1, -1, -1, dtype=np.intp)\n            uniques = self[::-1]\n        else:\n            codes = np.arange(len(self), dtype=np.intp)\n            uniques = self\n        return codes, uniques\n\n    def equals(self, other: object) -> bool:\n        """\n        Determines if two Index objects contain the same elements.\n        """\n        if isinstance(other, RangeIndex):\n            return self._range == other._range\n        return super().equals(other)\n\n    # error: Signature of "sort_values" incompatible with supertype "Index"\n    @overload  # type: ignore[override]\n    def sort_values(\n        self,\n        *,\n        return_indexer: Literal[False] = ...,\n        ascending: bool = ...,\n        na_position: NaPosition = ...,\n        key: Callable | None = ...,\n    ) -> Self: ...\n\n    @overload\n    def sort_values(\n        self,\n        *,\n        return_indexer: Literal[True],\n        ascending: bool = ...,\n        na_position: NaPosition = ...,\n        key: Callable | None = ...,\n    ) -> tuple[Self, np.ndarray | RangeIndex]: ...\n\n    @overload\n    def sort_values(\n        self,\n        *,\n        return_indexer: bool = ...,\n        ascending: bool = ...,\n        na_position: NaPosition = ...,\n        key: Callable | None = ...,\n    ) -> Self | tuple[Self, np.ndarray | RangeIndex]: ...\n\n    def sort_values(\n        self,\n        *,\n        return_indexer: bool = False,\n        ascending: bool = True,\n        na_position: NaPosition = "last",\n        key: Callable | None = None,\n    ) -> Self | tuple[Self, np.ndarray | RangeIndex]:\n        if key is not None:\n            return super().sort_values(\n                return_indexer=return_indexer,\n                ascending=ascending,\n                na_position=na_position,\n                key=key,\n            )\n        else:\n            sorted_index = self\n            inverse_indexer = False\n            if ascending:\n                if self.step < 0:\n                    sorted_index = self[::-1]\n                    inverse_indexer = True\n            elif self.step > 0:\n                sorted_index = self[::-1]\n                inverse_indexer = True\n\n        if return_indexer:\n            if inverse_indexer:\n                rng = range(len(self) - 1, -1, -1)\n            else:\n                rng = range(len(self))\n            return sorted_index, RangeIndex(rng)\n        else:\n            return sorted_index\n\n    # --------------------------------------------------------------------\n    # Set Operations\n\n    def _intersection(self, other: Index, sort: bool = False):\n        # caller is responsible for checking self and other are both non-empty\n\n        if not isinstance(other, RangeIndex):\n            return super()._intersection(other, sort=sort)\n\n        first = self._range[::-1] if self.step < 0 else self._range\n        second = other._range[::-1] if other.step < 0 else other._range\n\n        # check whether intervals intersect\n        # deals with in- and decreasing ranges\n        int_low = max(first.start, second.start)\n        int_high = min(first.stop, second.stop)\n        if int_high <= int_low:\n            return self._simple_new(_empty_range)\n\n        # Method hint: linear Diophantine equation\n        # solve intersection problem\n        # performance hint: for identical step sizes, could use\n        # cheaper alternative\n        gcd, s, _ = self._extended_gcd(first.step, second.step)\n\n        # check whether element sets intersect\n        if (first.start - second.start) % gcd:\n            return self._simple_new(_empty_range)\n\n        # calculate parameters for the RangeIndex describing the\n        # intersection disregarding the lower bounds\n        tmp_start = first.start + (second.start - first.start) * first.step // gcd * s\n        new_step = first.step * second.step // gcd\n\n        # adjust index to limiting interval\n        new_start = min_fitting_element(tmp_start, new_step, int_low)\n        new_range = range(new_start, int_high, new_step)\n\n        if (self.step < 0 and other.step < 0) is not (new_range.step < 0):\n            new_range = new_range[::-1]\n\n        return self._simple_new(new_range)\n\n    def _extended_gcd(self, a: int, b: int) -> tuple[int, int, int]:\n        """\n        Extended Euclidean algorithms to solve Bezout\'s identity:\n           a*x + b*y = gcd(x, y)\n        Finds one particular solution for x, y: s, t\n        Returns: gcd, s, t\n        """\n        s, old_s = 0, 1\n        t, old_t = 1, 0\n        r, old_r = b, a\n        while r:\n            quotient = old_r // r\n            old_r, r = r, old_r - quotient * r\n            old_s, s = s, old_s - quotient * s\n            old_t, t = t, old_t - quotient * t\n        return old_r, old_s, old_t\n\n    def _range_in_self(self, other: range) -> bool:\n        """Check if other range is contained in self"""\n        # https://stackoverflow.com/a/32481015\n        if not other:\n            return True\n        if not self._range:\n            return False\n        if len(other) > 1 and other.step % self._range.step:\n            return False\n        return other.start in self._range and other[-1] in self._range\n\n    def _union(self, other: Index, sort: bool | None):\n        """\n        Form the union of two Index objects and sorts if possible\n\n        Parameters\n        ----------\n        other : Index or array-like\n\n        sort : bool or None, default None\n            Whether to sort (monotonically increasing) the resulting index.\n            ``sort=None|True`` returns a ``RangeIndex`` if possible or a sorted\n            ``Index`` with an int64 dtype if not.\n            ``sort=False`` can return a ``RangeIndex`` if self is monotonically\n            increasing and other is fully contained in self. Otherwise, returns\n            an unsorted ``Index`` with an int64 dtype.\n\n        Returns\n        -------\n        union : Index\n        """\n        if isinstance(other, RangeIndex):\n            if sort in (None, True) or (\n                sort is False and self.step > 0 and self._range_in_self(other._range)\n            ):\n                # GH 47557: Can still return a RangeIndex\n                # if other range in self and sort=False\n                start_s, step_s = self.start, self.step\n                end_s = self.start + self.step * (len(self) - 1)\n                start_o, step_o = other.start, other.step\n                end_o = other.start + other.step * (len(other) - 1)\n                if self.step < 0:\n                    start_s, step_s, end_s = end_s, -step_s, start_s\n                if other.step < 0:\n                    start_o, step_o, end_o = end_o, -step_o, start_o\n                if len(self) == 1 and len(other) == 1:\n                    step_s = step_o = abs(self.start - other.start)\n                elif len(self) == 1:\n                    step_s = step_o\n                elif len(other) == 1:\n                    step_o = step_s\n                start_r = min(start_s, start_o)\n                end_r = max(end_s, end_o)\n                if step_o == step_s:\n                    if (\n                        (start_s - start_o) % step_s == 0\n                        and (start_s - end_o) <= step_s\n                        and (start_o - end_s) <= step_s\n                    ):\n                        return type(self)(start_r, end_r + step_s, step_s)\n                    if (\n                        (step_s % 2 == 0)\n                        and (abs(start_s - start_o) == step_s / 2)\n                        and (abs(end_s - end_o) == step_s / 2)\n                    ):\n                        # e.g. range(0, 10, 2) and range(1, 11, 2)\n                        #  but not range(0, 20, 4) and range(1, 21, 4) GH#44019\n                        return type(self)(start_r, end_r + step_s / 2, step_s / 2)\n\n                elif step_o % step_s == 0:\n                    if (\n                        (start_o - start_s) % step_s == 0\n                        and (start_o + step_s >= start_s)\n                        and (end_o - step_s <= end_s)\n                    ):\n                        return type(self)(start_r, end_r + step_s, step_s)\n                elif step_s % step_o == 0:\n                    if (\n                        (start_s - start_o) % step_o == 0\n                        and (start_s + step_o >= start_o)\n                        and (end_s - step_o <= end_o)\n                    ):\n                        return type(self)(start_r, end_r + step_o, step_o)\n\n        return super()._union(other, sort=sort)\n\n    def _difference(self, other, sort=None):\n        # optimized set operation if we have another RangeIndex\n        self._validate_sort_keyword(sort)\n        self._assert_can_do_setop(other)\n        other, result_name = self._convert_can_do_setop(other)\n\n        if not isinstance(other, RangeIndex):\n            return super()._difference(other, sort=sort)\n\n        if sort is not False and self.step < 0:\n            return self[::-1]._difference(other)\n\n        res_name = ops.get_op_result_name(self, other)\n\n        first = self._range[::-1] if self.step < 0 else self._range\n        overlap = self.intersection(other)\n        if overlap.step < 0:\n            overlap = overlap[::-1]\n\n        if len(overlap) == 0:\n            return self.rename(name=res_name)\n        if len(overlap) == len(self):\n            return self[:0].rename(res_name)\n\n        # overlap.step will always be a multiple of self.step (see _intersection)\n\n        if len(overlap) == 1:\n            if overlap[0] == self[0]:\n                return self[1:]\n\n            elif overlap[0] == self[-1]:\n                return self[:-1]\n\n            elif len(self) == 3 and overlap[0] == self[1]:\n                return self[::2]\n\n            else:\n                return super()._difference(other, sort=sort)\n\n        elif len(overlap) == 2 and overlap[0] == first[0] and overlap[-1] == first[-1]:\n            # e.g. range(-8, 20, 7) and range(13, -9, -3)\n            return self[1:-1]\n\n        if overlap.step == first.step:\n            if overlap[0] == first.start:\n                # The difference is everything after the intersection\n                new_rng = range(overlap[-1] + first.step, first.stop, first.step)\n            elif overlap[-1] == first[-1]:\n                # The difference is everything before the intersection\n                new_rng = range(first.start, overlap[0], first.step)\n            elif overlap._range == first[1:-1]:\n                # e.g. range(4) and range(1, 3)\n                step = len(first) - 1\n                new_rng = first[::step]\n            else:\n                # The difference is not range-like\n                # e.g. range(1, 10, 1) and range(3, 7, 1)\n                return super()._difference(other, sort=sort)\n\n        else:\n            # We must have len(self) > 1, bc we ruled out above\n            #  len(overlap) == 0 and len(overlap) == len(self)\n            assert len(self) > 1\n\n            if overlap.step == first.step * 2:\n                if overlap[0] == first[0] and overlap[-1] in (first[-1], first[-2]):\n                    # e.g. range(1, 10, 1) and range(1, 10, 2)\n                    new_rng = first[1::2]\n\n                elif overlap[0] == first[1] and overlap[-1] in (first[-1], first[-2]):\n                    # e.g. range(1, 10, 1) and range(2, 10, 2)\n                    new_rng = first[::2]\n\n                else:\n                    # We can get here with  e.g. range(20) and range(0, 10, 2)\n                    return super()._difference(other, sort=sort)\n\n            else:\n                # e.g. range(10) and range(0, 10, 3)\n                return super()._difference(other, sort=sort)\n\n        if first is not self._range:\n            new_rng = new_rng[::-1]\n        new_index = type(self)._simple_new(new_rng, name=res_name)\n\n        return new_index\n\n    def symmetric_difference(\n        self, other, result_name: Hashable | None = None, sort=None\n    ) -> Index:\n        if not isinstance(other, RangeIndex) or sort is not None:\n            return super().symmetric_difference(other, result_name, sort)\n\n        left = self.difference(other)\n        right = other.difference(self)\n        result = left.union(right)\n\n        if result_name is not None:\n            result = result.rename(result_name)\n        return result\n\n    def _join_empty(\n        self, other: Index, how: JoinHow, sort: bool\n    ) -> tuple[Index, npt.NDArray[np.intp] | None, npt.NDArray[np.intp] | None]:\n        if not isinstance(other, RangeIndex) and other.dtype.kind == "i":\n            other = self._shallow_copy(other._values, name=other.name)\n        return super()._join_empty(other, how=how, sort=sort)\n\n    def _join_monotonic(\n        self, other: Index, how: JoinHow = "left"\n    ) -> tuple[Index, npt.NDArray[np.intp] | None, npt.NDArray[np.intp] | None]:\n        # This currently only gets called for the monotonic increasing case\n        if not isinstance(other, type(self)):\n            maybe_ri = self._shallow_copy(other._values, name=other.name)\n            if not isinstance(maybe_ri, type(self)):\n                return super()._join_monotonic(other, how=how)\n            other = maybe_ri\n\n        if self.equals(other):\n            ret_index = other if how == "right" else self\n            return ret_index, None, None\n\n        if how == "left":\n            join_index = self\n            lidx = None\n            ridx = other.get_indexer(join_index)\n        elif how == "right":\n            join_index = other\n            lidx = self.get_indexer(join_index)\n            ridx = None\n        elif how == "inner":\n            join_index = self.intersection(other)\n            lidx = self.get_indexer(join_index)\n            ridx = other.get_indexer(join_index)\n        elif how == "outer":\n            join_index = self.union(other)\n            lidx = self.get_indexer(join_index)\n            ridx = other.get_indexer(join_index)\n\n        lidx = None if lidx is None else ensure_platform_int(lidx)\n        ridx = None if ridx is None else ensure_platform_int(ridx)\n        return join_index, lidx, ridx\n\n    # --------------------------------------------------------------------\n\n    # error: Return type "Index" of "delete" incompatible with return type\n    #  "RangeIndex" in supertype "Index"\n    def delete(self, loc) -> Index:  # type: ignore[override]\n        # In some cases we can retain RangeIndex, see also\n        #  DatetimeTimedeltaMixin._get_delete_Freq\n        if is_integer(loc):\n            if loc in (0, -len(self)):\n                return self[1:]\n            if loc in (-1, len(self) - 1):\n                return self[:-1]\n            if len(self) == 3 and loc in (1, -2):\n                return self[::2]\n\n        elif lib.is_list_like(loc):\n            slc = lib.maybe_indices_to_slice(np.asarray(loc, dtype=np.intp), len(self))\n\n            if isinstance(slc, slice):\n                # defer to RangeIndex._difference, which is optimized to return\n                #  a RangeIndex whenever possible\n                other = self[slc]\n                return self.difference(other, sort=False)\n\n        return super().delete(loc)\n\n    def insert(self, loc: int, item) -> Index:\n        if is_integer(item) or is_float(item):\n            # We can retain RangeIndex is inserting at the beginning or end,\n            #  or right in the middle.\n            if len(self) == 0 and loc == 0 and is_integer(item):\n                new_rng = range(item, item + self.step, self.step)\n                return type(self)._simple_new(new_rng, name=self._name)\n            elif len(self):\n                rng = self._range\n                if loc == 0 and item == self[0] - self.step:\n                    new_rng = range(rng.start - rng.step, rng.stop, rng.step)\n                    return type(self)._simple_new(new_rng, name=self._name)\n\n                elif loc == len(self) and item == self[-1] + self.step:\n                    new_rng = range(rng.start, rng.stop + rng.step, rng.step)\n                    return type(self)._simple_new(new_rng, name=self._name)\n\n                elif len(self) == 2 and item == self[0] + self.step / 2:\n                    # e.g. inserting 1 into [0, 2]\n                    step = int(self.step / 2)\n                    new_rng = range(self.start, self.stop, step)\n                    return type(self)._simple_new(new_rng, name=self._name)\n\n        return super().insert(loc, item)\n\n    def _concat(self, indexes: list[Index], name: Hashable) -> Index:\n        """\n        Overriding parent method for the case of all RangeIndex instances.\n\n        When all members of "indexes" are of type RangeIndex: result will be\n        RangeIndex if possible, Index with an int64 dtype otherwise. E.g.:\n        indexes = [RangeIndex(3), RangeIndex(3, 6)] -> RangeIndex(6)\n        indexes = [RangeIndex(3), RangeIndex(4, 6)] -> Index([0,1,2,4,5], dtype=\'int64\')\n        """\n        if not all(isinstance(x, RangeIndex) for x in indexes):\n            result = super()._concat(indexes, name)\n            if result.dtype.kind == "i":\n                return self._shallow_copy(result._values)\n            return result\n\n        elif len(indexes) == 1:\n            return indexes[0]\n\n        rng_indexes = cast(list[RangeIndex], indexes)\n\n        start = step = next_ = None\n\n        # Filter the empty indexes\n        non_empty_indexes = []\n        all_same_index = True\n        prev: RangeIndex | None = None\n        for obj in rng_indexes:\n            if len(obj):\n                non_empty_indexes.append(obj)\n                if all_same_index:\n                    if prev is not None:\n                        all_same_index = prev.equals(obj)\n                    else:\n                        prev = obj\n\n        for obj in non_empty_indexes:\n            rng = obj._range\n\n            if start is None:\n                # This is set by the first non-empty index\n                start = rng.start\n                if step is None and len(rng) > 1:\n                    step = rng.step\n            elif step is None:\n                # First non-empty index had only one element\n                if rng.start == start:\n                    if all_same_index:\n                        values = np.tile(\n                            non_empty_indexes[0]._values, len(non_empty_indexes)\n                        )\n                    else:\n                        values = np.concatenate([x._values for x in rng_indexes])\n                    result = self._constructor(values, copy=False)\n                    return result.rename(name)\n\n                step = rng.start - start\n\n            non_consecutive = (step != rng.step and len(rng) > 1) or (\n                next_ is not None and rng.start != next_\n            )\n            if non_consecutive:\n                if all_same_index:\n                    values = np.tile(\n                        non_empty_indexes[0]._values, len(non_empty_indexes)\n                    )\n                else:\n                    values = np.concatenate([x._values for x in rng_indexes])\n                result = self._constructor(values, copy=False)\n                return result.rename(name)\n\n            if step is not None:\n                next_ = rng[-1] + step\n\n        if non_empty_indexes:\n            # Get the stop value from "next" or alternatively\n            # from the last non-empty index\n            stop = non_empty_indexes[-1].stop if next_ is None else next_\n            if len(non_empty_indexes) == 1:\n                step = non_empty_indexes[0].step\n            return RangeIndex(start, stop, step, name=name)\n\n        # Here all "indexes" had 0 length, i.e. were empty.\n        # In this case return an empty range index.\n        return RangeIndex(_empty_range, name=name)\n\n    def __len__(self) -> int:\n        """\n        return the length of the RangeIndex\n        """\n        return len(self._range)\n\n    @property\n    def size(self) -> int:\n        return len(self)\n\n    def __getitem__(self, key):\n        """\n        Conserve RangeIndex type for scalar and slice keys.\n        """\n        key = lib.item_from_zerodim(key)\n        if key is Ellipsis:\n            key = slice(None)\n        if isinstance(key, slice):\n            return self._getitem_slice(key)\n        elif is_integer(key):\n            new_key = int(key)\n            try:\n                return self._range[new_key]\n            except IndexError as err:\n                raise IndexError(\n                    f"index {key} is out of bounds for axis 0 with size {len(self)}"\n                ) from err\n        elif is_scalar(key):\n            raise IndexError(\n                "only integers, slices (`:`), "\n                "ellipsis (`...`), numpy.newaxis (`None`) "\n                "and integer or boolean "\n                "arrays are valid indices"\n            )\n        elif com.is_bool_indexer(key):\n            if isinstance(getattr(key, "dtype", None), ExtensionDtype):\n                key = key.to_numpy(dtype=bool, na_value=False)\n            else:\n                key = np.asarray(key, dtype=bool)\n            check_array_indexer(self._range, key)  # type: ignore[arg-type]\n            key = np.flatnonzero(key)\n        try:\n            return self.take(key)\n        except (TypeError, ValueError):\n            return super().__getitem__(key)\n\n    def _getitem_slice(self, slobj: slice) -> Self:\n        """\n        Fastpath for __getitem__ when we know we have a slice.\n        """\n        res = self._range[slobj]\n        return type(self)._simple_new(res, name=self._name)\n\n    @unpack_zerodim_and_defer("__floordiv__")\n    def __floordiv__(self, other):\n        if is_integer(other) and other != 0:\n            if len(self) == 0 or (self.start % other == 0 and self.step % other == 0):\n                start = self.start // other\n                step = self.step // other\n                stop = start + len(self) * step\n                new_range = range(start, stop, step or 1)\n                return self._simple_new(new_range, name=self._name)\n            if len(self) == 1:\n                start = self.start // other\n                new_range = range(start, start + 1, 1)\n                return self._simple_new(new_range, name=self._name)\n\n        return super().__floordiv__(other)\n\n    # --------------------------------------------------------------------\n    # Reductions\n\n    def all(self, *args, **kwargs) -> bool:\n        return 0 not in self._range\n\n    def any(self, *args, **kwargs) -> bool:\n        return any(self._range)\n\n    # --------------------------------------------------------------------\n\n    # error: Return type "RangeIndex | Index" of "round" incompatible with\n    # return type "RangeIndex" in supertype "Index"\n    def round(self, decimals: int = 0) -> Self | Index:  # type: ignore[override]\n        """\n        Round each value in the Index to the given number of decimals.\n\n        Parameters\n        ----------\n        decimals : int, optional\n            Number of decimal places to round to. If decimals is negative,\n            it specifies the number of positions to the left of the decimal point\n            e.g. ``round(11.0, -1) == 10.0``.\n\n        Returns\n        -------\n        Index or RangeIndex\n            A new Index with the rounded values.\n\n        Examples\n        --------\n        >>> import pandas as pd\n        >>> idx = pd.RangeIndex(10, 30, 10)\n        >>> idx.round(decimals=-1)\n        RangeIndex(start=10, stop=30, step=10)\n        >>> idx = pd.RangeIndex(10, 15, 1)\n        >>> idx.round(decimals=-1)\n        Index([10, 10, 10, 10, 10], dtype=\'int64\')\n        """\n        if decimals >= 0:\n            return self.copy()\n        elif self.start % 10**-decimals == 0 and self.step % 10**-decimals == 0:\n            # e.g. RangeIndex(10, 30, 10).round(-1) doesn\'t need rounding\n            return self.copy()\n        else:\n            return super().round(decimals=decimals)\n\n    def _cmp_method(self, other, op):\n        if isinstance(other, RangeIndex) and self._range == other._range:\n            # Both are immutable so if ._range attr. are equal, shortcut is possible\n            return super()._cmp_method(self, op)\n        return super()._cmp_method(other, op)\n\n    def _arith_method(self, other, op):\n        """\n        Parameters\n        ----------\n        other : Any\n        op : callable that accepts 2 params\n            perform the binary op\n        """\n\n        if isinstance(other, ABCTimedeltaIndex):\n            # Defer to TimedeltaIndex implementation\n            return NotImplemented\n        elif isinstance(other, (timedelta, np.timedelta64)):\n            # GH#19333 is_integer evaluated True on timedelta64,\n            # so we need to catch these explicitly\n            return super()._arith_method(other, op)\n        elif lib.is_np_dtype(getattr(other, "dtype", None), "m"):\n            # Must be an np.ndarray; GH#22390\n            return super()._arith_method(other, op)\n\n        if op in [\n            operator.pow,\n            ops.rpow,\n            operator.mod,\n            ops.rmod,\n            operator.floordiv,\n            ops.rfloordiv,\n            divmod,\n            ops.rdivmod,\n        ]:\n            return super()._arith_method(other, op)\n\n        step: Callable | None = None\n        if op in [operator.mul, ops.rmul, operator.truediv, ops.rtruediv]:\n            step = op\n\n        # TODO: if other is a RangeIndex we may have more efficient options\n        right = extract_array(other, extract_numpy=True, extract_range=True)\n        left = self\n\n        try:\n            # apply if we have an override\n            if step:\n                with np.errstate(all="ignore"):\n                    rstep = step(left.step, right)\n\n                # we don\'t have a representable op\n                # so return a base index\n                if not is_integer(rstep) or not rstep:\n                    raise ValueError\n\n            # GH#53255\n            else:\n                rstep = -left.step if op == ops.rsub else left.step\n\n            with np.errstate(all="ignore"):\n                rstart = op(left.start, right)\n                rstop = op(left.stop, right)\n\n            res_name = ops.get_op_result_name(self, other)\n            result = type(self)(rstart, rstop, rstep, name=res_name)\n\n            # for compat with numpy / Index with int64 dtype\n            # even if we can represent as a RangeIndex, return\n            # as a float64 Index if we have float-like descriptors\n            if not all(is_integer(x) for x in [rstart, rstop, rstep]):\n                result = result.astype("float64")\n\n            return result\n\n        except (ValueError, TypeError, ZeroDivisionError):\n            # test_arithmetic_explicit_conversions\n            return super()._arith_method(other, op)\n\n    def __abs__(self) -> Self | Index:\n        if len(self) == 0 or self.min() >= 0:\n            return self.copy()\n        elif self.max() <= 0:\n            return -self\n        else:\n            return super().__abs__()\n\n    def __neg__(self) -> Self:\n        rng = range(-self.start, -self.stop, -self.step)\n        return self._simple_new(rng, name=self.name)\n\n    def __pos__(self) -> Self:\n        return self.copy()\n\n    def __invert__(self) -> Self:\n        if len(self) == 0:\n            return self.copy()\n        rng = range(~self.start, ~self.stop, -self.step)\n        return self._simple_new(rng, name=self.name)\n\n    # error: Return type "Index" of "take" incompatible with return type\n    # "RangeIndex" in supertype "Index"\n    def take(  # type: ignore[override]\n        self,\n        indices,\n        axis: Axis = 0,\n        allow_fill: bool = True,\n        fill_value=None,\n        **kwargs,\n    ) -> Self | Index:\n        if kwargs:\n            nv.validate_take((), kwargs)\n        if is_scalar(indices):\n            raise TypeError("Expected indices to be array-like")\n        indices = ensure_platform_int(indices)\n\n        # raise an exception if allow_fill is True and fill_value is not None\n        self._maybe_disallow_fill(allow_fill, fill_value, indices)\n\n        if len(indices) == 0:\n            return type(self)(_empty_range, name=self.name)\n        else:\n            ind_max = indices.max()\n            if ind_max >= len(self):\n                raise IndexError(\n                    f"index {ind_max} is out of bounds for axis 0 with size {len(self)}"\n                )\n            ind_min = indices.min()\n            if ind_min < -len(self):\n                raise IndexError(\n                    f"index {ind_min} is out of bounds for axis 0 with size {len(self)}"\n                )\n            taken = indices.astype(self.dtype, casting="safe")\n            if ind_min < 0:\n                taken %= len(self)\n            if self.step != 1:\n                taken *= self.step\n            if self.start != 0:\n                taken += self.start\n\n        return self._shallow_copy(taken, name=self.name)\n\n    def value_counts(\n        self,\n        normalize: bool = False,\n        sort: bool = True,\n        ascending: bool = False,\n        bins=None,\n        dropna: bool = True,\n    ) -> Series:\n        from pandas import Series\n\n        if bins is not None:\n            return super().value_counts(\n                normalize=normalize,\n                sort=sort,\n                ascending=ascending,\n                bins=bins,\n                dropna=dropna,\n            )\n        name = "proportion" if normalize else "count"\n        data: npt.NDArray[np.floating] | npt.NDArray[np.signedinteger] = np.ones(\n            len(self), dtype=np.int64\n        )\n        if normalize:\n            data = data / len(self)\n        return Series(data, index=self.copy(), name=name)\n\n    def searchsorted(  # type: ignore[override]\n        self,\n        value,\n        side: Literal["left", "right"] = "left",\n        sorter: NumpySorter | None = None,\n    ) -> npt.NDArray[np.intp] | np.intp:\n        if side not in {"left", "right"} or sorter is not None:\n            return super().searchsorted(value=value, side=side, sorter=sorter)\n\n        was_scalar = False\n        if is_scalar(value):\n            was_scalar = True\n            array_value = np.array([value])\n        else:\n            array_value = np.asarray(value)\n        if array_value.dtype.kind not in "iu":\n            return super().searchsorted(value=value, side=side, sorter=sorter)\n\n        if flip := (self.step < 0):\n            rng = self._range[::-1]\n            start = rng.start\n            step = rng.step\n            shift = side == "right"\n        else:\n            start = self.start\n            step = self.step\n            shift = side == "left"\n        result = (array_value - start - int(shift)) // step + 1\n        if flip:\n            result = len(self) - result\n        result = np.maximum(np.minimum(result, len(self)), 0)\n        if was_scalar:\n            return np.intp(result.item())\n        return result.astype(np.intp, copy=False)\n',
            'pandas/tests/frame/methods/test_sort_index.py': 'import numpy as np\nimport pytest\n\nimport pandas as pd\nfrom pandas import (\n    CategoricalDtype,\n    CategoricalIndex,\n    DataFrame,\n    IntervalIndex,\n    MultiIndex,\n    RangeIndex,\n    Series,\n    Timestamp,\n)\nimport pandas._testing as tm\n\n\nclass TestDataFrameSortIndex:\n    def test_sort_index_and_reconstruction_doc_example(self):\n        # doc example\n        df = DataFrame(\n            {"value": [1, 2, 3, 4]},\n            index=MultiIndex(\n                levels=[["a", "b"], ["bb", "aa"]], codes=[[0, 0, 1, 1], [0, 1, 0, 1]]\n            ),\n        )\n        assert df.index._is_lexsorted()\n        assert not df.index.is_monotonic_increasing\n\n        # sort it\n        expected = DataFrame(\n            {"value": [2, 1, 4, 3]},\n            index=MultiIndex(\n                levels=[["a", "b"], ["aa", "bb"]], codes=[[0, 0, 1, 1], [0, 1, 0, 1]]\n            ),\n        )\n        result = df.sort_index()\n        assert result.index.is_monotonic_increasing\n        tm.assert_frame_equal(result, expected)\n\n        # reconstruct\n        result = df.sort_index().copy()\n        result.index = result.index._sort_levels_monotonic()\n        assert result.index.is_monotonic_increasing\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_non_existent_label_multiindex(self):\n        # GH#12261\n        df = DataFrame(0, columns=[], index=MultiIndex.from_product([[], []]))\n        with tm.assert_produces_warning(None):\n            df.loc["b", "2"] = 1\n            df.loc["a", "3"] = 1\n        result = df.sort_index().index.is_monotonic_increasing\n        assert result is True\n\n    def test_sort_index_reorder_on_ops(self):\n        # GH#15687\n        df = DataFrame(\n            np.random.default_rng(2).standard_normal((8, 2)),\n            index=MultiIndex.from_product(\n                [["a", "b"], ["big", "small"], ["red", "blu"]],\n                names=["letter", "size", "color"],\n            ),\n            columns=["near", "far"],\n        )\n        df = df.sort_index()\n\n        def my_func(group):\n            group.index = ["newz", "newa"]\n            return group\n\n        result = df.groupby(level=["letter", "size"]).apply(my_func).sort_index()\n        expected = MultiIndex.from_product(\n            [["a", "b"], ["big", "small"], ["newa", "newz"]],\n            names=["letter", "size", None],\n        )\n\n        tm.assert_index_equal(result.index, expected)\n\n    def test_sort_index_nan_multiindex(self):\n        # GH#14784\n        # incorrect sorting w.r.t. nans\n        tuples = [[12, 13], [np.nan, np.nan], [np.nan, 3], [1, 2]]\n        mi = MultiIndex.from_tuples(tuples)\n\n        df = DataFrame(np.arange(16).reshape(4, 4), index=mi, columns=list("ABCD"))\n        s = Series(np.arange(4), index=mi)\n\n        df2 = DataFrame(\n            {\n                "date": pd.DatetimeIndex(\n                    [\n                        "20121002",\n                        "20121007",\n                        "20130130",\n                        "20130202",\n                        "20130305",\n                        "20121002",\n                        "20121207",\n                        "20130130",\n                        "20130202",\n                        "20130305",\n                        "20130202",\n                        "20130305",\n                    ]\n                ),\n                "user_id": [1, 1, 1, 1, 1, 3, 3, 3, 5, 5, 5, 5],\n                "whole_cost": [\n                    1790,\n                    np.nan,\n                    280,\n                    259,\n                    np.nan,\n                    623,\n                    90,\n                    312,\n                    np.nan,\n                    301,\n                    359,\n                    801,\n                ],\n                "cost": [12, 15, 10, 24, 39, 1, 0, np.nan, 45, 34, 1, 12],\n            }\n        ).set_index(["date", "user_id"])\n\n        # sorting frame, default nan position is last\n        result = df.sort_index()\n        expected = df.iloc[[3, 0, 2, 1], :]\n        tm.assert_frame_equal(result, expected)\n\n        # sorting frame, nan position last\n        result = df.sort_index(na_position="last")\n        expected = df.iloc[[3, 0, 2, 1], :]\n        tm.assert_frame_equal(result, expected)\n\n        # sorting frame, nan position first\n        result = df.sort_index(na_position="first")\n        expected = df.iloc[[1, 2, 3, 0], :]\n        tm.assert_frame_equal(result, expected)\n\n        # sorting frame with removed rows\n        result = df2.dropna().sort_index()\n        expected = df2.sort_index().dropna()\n        tm.assert_frame_equal(result, expected)\n\n        # sorting series, default nan position is last\n        result = s.sort_index()\n        expected = s.iloc[[3, 0, 2, 1]]\n        tm.assert_series_equal(result, expected)\n\n        # sorting series, nan position last\n        result = s.sort_index(na_position="last")\n        expected = s.iloc[[3, 0, 2, 1]]\n        tm.assert_series_equal(result, expected)\n\n        # sorting series, nan position first\n        result = s.sort_index(na_position="first")\n        expected = s.iloc[[1, 2, 3, 0]]\n        tm.assert_series_equal(result, expected)\n\n    def test_sort_index_nan(self):\n        # GH#3917\n\n        # Test DataFrame with nan label\n        df = DataFrame(\n            {"A": [1, 2, np.nan, 1, 6, 8, 4], "B": [9, np.nan, 5, 2, 5, 4, 5]},\n            index=[1, 2, 3, 4, 5, 6, np.nan],\n        )\n\n        # NaN label, ascending=True, na_position=\'last\'\n        sorted_df = df.sort_index(kind="quicksort", ascending=True, na_position="last")\n        expected = DataFrame(\n            {"A": [1, 2, np.nan, 1, 6, 8, 4], "B": [9, np.nan, 5, 2, 5, 4, 5]},\n            index=[1, 2, 3, 4, 5, 6, np.nan],\n        )\n        tm.assert_frame_equal(sorted_df, expected)\n\n        # NaN label, ascending=True, na_position=\'first\'\n        sorted_df = df.sort_index(na_position="first")\n        expected = DataFrame(\n            {"A": [4, 1, 2, np.nan, 1, 6, 8], "B": [5, 9, np.nan, 5, 2, 5, 4]},\n            index=[np.nan, 1, 2, 3, 4, 5, 6],\n        )\n        tm.assert_frame_equal(sorted_df, expected)\n\n        # NaN label, ascending=False, na_position=\'last\'\n        sorted_df = df.sort_index(kind="quicksort", ascending=False)\n        expected = DataFrame(\n            {"A": [8, 6, 1, np.nan, 2, 1, 4], "B": [4, 5, 2, 5, np.nan, 9, 5]},\n            index=[6, 5, 4, 3, 2, 1, np.nan],\n        )\n        tm.assert_frame_equal(sorted_df, expected)\n\n        # NaN label, ascending=False, na_position=\'first\'\n        sorted_df = df.sort_index(\n            kind="quicksort", ascending=False, na_position="first"\n        )\n        expected = DataFrame(\n            {"A": [4, 8, 6, 1, np.nan, 2, 1], "B": [5, 4, 5, 2, 5, np.nan, 9]},\n            index=[np.nan, 6, 5, 4, 3, 2, 1],\n        )\n        tm.assert_frame_equal(sorted_df, expected)\n\n    def test_sort_index_multi_index(self):\n        # GH#25775, testing that sorting by index works with a multi-index.\n        df = DataFrame(\n            {"a": [3, 1, 2], "b": [0, 0, 0], "c": [0, 1, 2], "d": list("abc")}\n        )\n        result = df.set_index(list("abc")).sort_index(level=list("ba"))\n\n        expected = DataFrame(\n            {"a": [1, 2, 3], "b": [0, 0, 0], "c": [1, 2, 0], "d": list("bca")}\n        )\n        expected = expected.set_index(list("abc"))\n\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_inplace(self):\n        frame = DataFrame(\n            np.random.default_rng(2).standard_normal((4, 4)),\n            index=[1, 2, 3, 4],\n            columns=["A", "B", "C", "D"],\n        )\n\n        # axis=0\n        unordered = frame.loc[[3, 2, 4, 1]]\n        a_values = unordered["A"]\n        df = unordered.copy()\n        return_value = df.sort_index(inplace=True)\n        assert return_value is None\n        expected = frame\n        tm.assert_frame_equal(df, expected)\n        # GH 44153 related\n        # Used to be a_id != id(df["A"]), but flaky in the CI\n        assert a_values is not df["A"]\n\n        df = unordered.copy()\n        return_value = df.sort_index(ascending=False, inplace=True)\n        assert return_value is None\n        expected = frame[::-1]\n        tm.assert_frame_equal(df, expected)\n\n        # axis=1\n        unordered = frame.loc[:, ["D", "B", "C", "A"]]\n        df = unordered.copy()\n        return_value = df.sort_index(axis=1, inplace=True)\n        assert return_value is None\n        expected = frame\n        tm.assert_frame_equal(df, expected)\n\n        df = unordered.copy()\n        return_value = df.sort_index(axis=1, ascending=False, inplace=True)\n        assert return_value is None\n        expected = frame.iloc[:, ::-1]\n        tm.assert_frame_equal(df, expected)\n\n    def test_sort_index_different_sortorder(self):\n        A = np.arange(20).repeat(5)\n        B = np.tile(np.arange(5), 20)\n\n        indexer = np.random.default_rng(2).permutation(100)\n        A = A.take(indexer)\n        B = B.take(indexer)\n\n        df = DataFrame(\n            {"A": A, "B": B, "C": np.random.default_rng(2).standard_normal(100)}\n        )\n\n        ex_indexer = np.lexsort((df.B.max() - df.B, df.A))\n        expected = df.take(ex_indexer)\n\n        # test with multiindex, too\n        idf = df.set_index(["A", "B"])\n\n        result = idf.sort_index(ascending=[1, 0])\n        expected = idf.take(ex_indexer)\n        tm.assert_frame_equal(result, expected)\n\n        # also, Series!\n        result = idf["C"].sort_index(ascending=[1, 0])\n        tm.assert_series_equal(result, expected["C"])\n\n    def test_sort_index_level(self):\n        mi = MultiIndex.from_tuples([[1, 1, 3], [1, 1, 1]], names=list("ABC"))\n        df = DataFrame([[1, 2], [3, 4]], mi)\n\n        result = df.sort_index(level="A", sort_remaining=False)\n        expected = df\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(level=["A", "B"], sort_remaining=False)\n        expected = df\n        tm.assert_frame_equal(result, expected)\n\n        # Error thrown by sort_index when\n        # first index is sorted last (GH#26053)\n        result = df.sort_index(level=["C", "B", "A"])\n        expected = df.iloc[[1, 0]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(level=["B", "C", "A"])\n        expected = df.iloc[[1, 0]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(level=["C", "A"])\n        expected = df.iloc[[1, 0]]\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_categorical_index(self):\n        df = DataFrame(\n            {\n                "A": np.arange(6, dtype="int64"),\n                "B": Series(list("aabbca")).astype(CategoricalDtype(list("cab"))),\n            }\n        ).set_index("B")\n\n        result = df.sort_index()\n        expected = df.iloc[[4, 0, 1, 5, 2, 3]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(ascending=False)\n        expected = df.iloc[[2, 3, 0, 1, 5, 4]]\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index(self):\n        # GH#13496\n\n        frame = DataFrame(\n            np.arange(16).reshape(4, 4),\n            index=[1, 2, 3, 4],\n            columns=["A", "B", "C", "D"],\n        )\n\n        # axis=0 : sort rows by index labels\n        unordered = frame.loc[[3, 2, 4, 1]]\n        result = unordered.sort_index(axis=0)\n        expected = frame\n        tm.assert_frame_equal(result, expected)\n\n        result = unordered.sort_index(ascending=False)\n        expected = frame[::-1]\n        tm.assert_frame_equal(result, expected)\n\n        # axis=1 : sort columns by column names\n        unordered = frame.iloc[:, [2, 1, 3, 0]]\n        result = unordered.sort_index(axis=1)\n        tm.assert_frame_equal(result, frame)\n\n        result = unordered.sort_index(axis=1, ascending=False)\n        expected = frame.iloc[:, ::-1]\n        tm.assert_frame_equal(result, expected)\n\n    @pytest.mark.parametrize("level", ["A", 0])  # GH#21052\n    def test_sort_index_multiindex(self, level):\n        # GH#13496\n\n        # sort rows by specified level of multi-index\n        mi = MultiIndex.from_tuples(\n            [[2, 1, 3], [2, 1, 2], [1, 1, 1]], names=list("ABC")\n        )\n        df = DataFrame([[1, 2], [3, 4], [5, 6]], index=mi)\n\n        expected_mi = MultiIndex.from_tuples(\n            [[1, 1, 1], [2, 1, 2], [2, 1, 3]], names=list("ABC")\n        )\n        expected = DataFrame([[5, 6], [3, 4], [1, 2]], index=expected_mi)\n        result = df.sort_index(level=level)\n        tm.assert_frame_equal(result, expected)\n\n        # sort_remaining=False\n        expected_mi = MultiIndex.from_tuples(\n            [[1, 1, 1], [2, 1, 3], [2, 1, 2]], names=list("ABC")\n        )\n        expected = DataFrame([[5, 6], [1, 2], [3, 4]], index=expected_mi)\n        result = df.sort_index(level=level, sort_remaining=False)\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_intervalindex(self):\n        # this is a de-facto sort via unstack\n        # confirming that we sort in the order of the bins\n        y = Series(np.random.default_rng(2).standard_normal(100))\n        x1 = Series(np.sign(np.random.default_rng(2).standard_normal(100)))\n        x2 = pd.cut(\n            Series(np.random.default_rng(2).standard_normal(100)),\n            bins=[-3, -0.5, 0, 0.5, 3],\n        )\n        model = pd.concat([y, x1, x2], axis=1, keys=["Y", "X1", "X2"])\n\n        result = model.groupby(["X1", "X2"], observed=True).mean().unstack()\n        expected = IntervalIndex.from_tuples(\n            [(-3.0, -0.5), (-0.5, 0.0), (0.0, 0.5), (0.5, 3.0)], closed="right"\n        )\n        result = result.columns.levels[1].categories\n        tm.assert_index_equal(result, expected)\n\n    @pytest.mark.parametrize("inplace", [True, False])\n    @pytest.mark.parametrize(\n        "original_dict, sorted_dict, ascending, ignore_index, output_index",\n        [\n            ({"A": [1, 2, 3]}, {"A": [2, 3, 1]}, False, True, [0, 1, 2]),\n            ({"A": [1, 2, 3]}, {"A": [1, 3, 2]}, True, True, [0, 1, 2]),\n            ({"A": [1, 2, 3]}, {"A": [2, 3, 1]}, False, False, [5, 3, 2]),\n            ({"A": [1, 2, 3]}, {"A": [1, 3, 2]}, True, False, [2, 3, 5]),\n        ],\n    )\n    def test_sort_index_ignore_index(\n        self, inplace, original_dict, sorted_dict, ascending, ignore_index, output_index\n    ):\n        # GH 30114\n        original_index = [2, 5, 3]\n        df = DataFrame(original_dict, index=original_index)\n        expected_df = DataFrame(sorted_dict, index=output_index)\n        kwargs = {\n            "ascending": ascending,\n            "ignore_index": ignore_index,\n            "inplace": inplace,\n        }\n\n        if inplace:\n            result_df = df.copy()\n            result_df.sort_index(**kwargs)\n        else:\n            result_df = df.sort_index(**kwargs)\n\n        tm.assert_frame_equal(result_df, expected_df)\n        tm.assert_frame_equal(df, DataFrame(original_dict, index=original_index))\n\n    @pytest.mark.parametrize("inplace", [True, False])\n    @pytest.mark.parametrize("ignore_index", [True, False])\n    def test_respect_ignore_index(self, inplace, ignore_index):\n        # GH 43591\n        df = DataFrame({"a": [1, 2, 3]}, index=RangeIndex(4, -1, -2))\n        result = df.sort_index(\n            ascending=False, ignore_index=ignore_index, inplace=inplace\n        )\n\n        if inplace:\n            result = df\n        if ignore_index:\n            expected = DataFrame({"a": [1, 2, 3]})\n        else:\n            expected = DataFrame({"a": [1, 2, 3]}, index=RangeIndex(4, -1, -2))\n\n        tm.assert_frame_equal(result, expected)\n\n    @pytest.mark.parametrize("inplace", [True, False])\n    @pytest.mark.parametrize(\n        "original_dict, sorted_dict, ascending, ignore_index, output_index",\n        [\n            (\n                {"M1": [1, 2], "M2": [3, 4]},\n                {"M1": [1, 2], "M2": [3, 4]},\n                True,\n                True,\n                [0, 1],\n            ),\n            (\n                {"M1": [1, 2], "M2": [3, 4]},\n                {"M1": [2, 1], "M2": [4, 3]},\n                False,\n                True,\n                [0, 1],\n            ),\n            (\n                {"M1": [1, 2], "M2": [3, 4]},\n                {"M1": [1, 2], "M2": [3, 4]},\n                True,\n                False,\n                MultiIndex.from_tuples([(2, 1), (3, 4)], names=list("AB")),\n            ),\n            (\n                {"M1": [1, 2], "M2": [3, 4]},\n                {"M1": [2, 1], "M2": [4, 3]},\n                False,\n                False,\n                MultiIndex.from_tuples([(3, 4), (2, 1)], names=list("AB")),\n            ),\n        ],\n    )\n    def test_sort_index_ignore_index_multi_index(\n        self, inplace, original_dict, sorted_dict, ascending, ignore_index, output_index\n    ):\n        # GH 30114, this is to test ignore_index on MultiIndex of index\n        mi = MultiIndex.from_tuples([(2, 1), (3, 4)], names=list("AB"))\n        df = DataFrame(original_dict, index=mi)\n        expected_df = DataFrame(sorted_dict, index=output_index)\n\n        kwargs = {\n            "ascending": ascending,\n            "ignore_index": ignore_index,\n            "inplace": inplace,\n        }\n\n        if inplace:\n            result_df = df.copy()\n            result_df.sort_index(**kwargs)\n        else:\n            result_df = df.sort_index(**kwargs)\n\n        tm.assert_frame_equal(result_df, expected_df)\n        tm.assert_frame_equal(df, DataFrame(original_dict, index=mi))\n\n    def test_sort_index_categorical_multiindex(self):\n        # GH#15058\n        df = DataFrame(\n            {\n                "a": range(6),\n                "l1": pd.Categorical(\n                    ["a", "a", "b", "b", "c", "c"],\n                    categories=["c", "a", "b"],\n                    ordered=True,\n                ),\n                "l2": [0, 1, 0, 1, 0, 1],\n            }\n        )\n        result = df.set_index(["l1", "l2"]).sort_index()\n        expected = DataFrame(\n            [4, 5, 0, 1, 2, 3],\n            columns=["a"],\n            index=MultiIndex(\n                levels=[\n                    CategoricalIndex(\n                        ["c", "a", "b"],\n                        categories=["c", "a", "b"],\n                        ordered=True,\n                        name="l1",\n                        dtype="category",\n                    ),\n                    [0, 1],\n                ],\n                codes=[[0, 0, 1, 1, 2, 2], [0, 1, 0, 1, 0, 1]],\n                names=["l1", "l2"],\n            ),\n        )\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_and_reconstruction(self):\n        # GH#15622\n        # lexsortedness should be identical\n        # across MultiIndex construction methods\n\n        df = DataFrame([[1, 1], [2, 2]], index=list("ab"))\n        expected = DataFrame(\n            [[1, 1], [2, 2], [1, 1], [2, 2]],\n            index=MultiIndex.from_tuples(\n                [(0.5, "a"), (0.5, "b"), (0.8, "a"), (0.8, "b")]\n            ),\n        )\n        assert expected.index._is_lexsorted()\n\n        result = DataFrame(\n            [[1, 1], [2, 2], [1, 1], [2, 2]],\n            index=MultiIndex.from_product([[0.5, 0.8], list("ab")]),\n        )\n        result = result.sort_index()\n        assert result.index.is_monotonic_increasing\n\n        tm.assert_frame_equal(result, expected)\n\n        result = DataFrame(\n            [[1, 1], [2, 2], [1, 1], [2, 2]],\n            index=MultiIndex(\n                levels=[[0.5, 0.8], ["a", "b"]], codes=[[0, 0, 1, 1], [0, 1, 0, 1]]\n            ),\n        )\n        result = result.sort_index()\n        assert result.index._is_lexsorted()\n\n        tm.assert_frame_equal(result, expected)\n\n        concatted = pd.concat([df, df], keys=[0.8, 0.5])\n        result = concatted.sort_index()\n\n        assert result.index.is_monotonic_increasing\n\n        tm.assert_frame_equal(result, expected)\n\n        # GH#14015\n        df = DataFrame(\n            [[1, 2], [6, 7]],\n            columns=MultiIndex.from_tuples(\n                [(0, "20160811 12:00:00"), (0, "20160809 12:00:00")],\n                names=["l1", "Date"],\n            ),\n        )\n\n        df.columns = df.columns.set_levels(\n            pd.to_datetime(df.columns.levels[1]), level=1\n        )\n        assert not df.columns.is_monotonic_increasing\n        result = df.sort_index(axis=1)\n        assert result.columns.is_monotonic_increasing\n        result = df.sort_index(axis=1, level=1)\n        assert result.columns.is_monotonic_increasing\n\n    # TODO: better name, de-duplicate with test_sort_index_level above\n    def test_sort_index_level2(self, multiindex_dataframe_random_data):\n        frame = multiindex_dataframe_random_data\n\n        df = frame.copy()\n        df.index = np.arange(len(df))\n\n        # axis=1\n\n        # series\n        a_sorted = frame["A"].sort_index(level=0)\n\n        # preserve names\n        assert a_sorted.index.names == frame.index.names\n\n        # inplace\n        rs = frame.copy()\n        return_value = rs.sort_index(level=0, inplace=True)\n        assert return_value is None\n        tm.assert_frame_equal(rs, frame.sort_index(level=0))\n\n    def test_sort_index_level_large_cardinality(self):\n        # GH#2684 (int64)\n        index = MultiIndex.from_arrays([np.arange(4000)] * 3)\n        df = DataFrame(\n            np.random.default_rng(2).standard_normal(4000).astype("int64"), index=index\n        )\n\n        # it works!\n        result = df.sort_index(level=0)\n        assert result.index._lexsort_depth == 3\n\n        # GH#2684 (int32)\n        index = MultiIndex.from_arrays([np.arange(4000)] * 3)\n        df = DataFrame(\n            np.random.default_rng(2).standard_normal(4000).astype("int32"), index=index\n        )\n\n        # it works!\n        result = df.sort_index(level=0)\n        assert (result.dtypes.values == df.dtypes.values).all()\n        assert result.index._lexsort_depth == 3\n\n    def test_sort_index_level_by_name(self, multiindex_dataframe_random_data):\n        frame = multiindex_dataframe_random_data\n\n        frame.index.names = ["first", "second"]\n        result = frame.sort_index(level="second")\n        expected = frame.sort_index(level=1)\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_level_mixed(self, multiindex_dataframe_random_data):\n        frame = multiindex_dataframe_random_data\n\n        sorted_before = frame.sort_index(level=1)\n\n        df = frame.copy()\n        df["foo"] = "bar"\n        sorted_after = df.sort_index(level=1)\n        tm.assert_frame_equal(sorted_before, sorted_after.drop(["foo"], axis=1))\n\n        dft = frame.T\n        sorted_before = dft.sort_index(level=1, axis=1)\n        dft["foo", "three"] = "bar"\n\n        sorted_after = dft.sort_index(level=1, axis=1)\n        tm.assert_frame_equal(\n            sorted_before.drop([("foo", "three")], axis=1),\n            sorted_after.drop([("foo", "three")], axis=1),\n        )\n\n    def test_sort_index_preserve_levels(self, multiindex_dataframe_random_data):\n        frame = multiindex_dataframe_random_data\n\n        result = frame.sort_index()\n        assert result.index.names == frame.index.names\n\n    @pytest.mark.parametrize(\n        "gen,extra",\n        [\n            ([1.0, 3.0, 2.0, 5.0], 4.0),\n            ([1, 3, 2, 5], 4),\n            (\n                [\n                    Timestamp("20130101"),\n                    Timestamp("20130103"),\n                    Timestamp("20130102"),\n                    Timestamp("20130105"),\n                ],\n                Timestamp("20130104"),\n            ),\n            (["1one", "3one", "2one", "5one"], "4one"),\n        ],\n    )\n    def test_sort_index_multilevel_repr_8017(self, gen, extra):\n        data = np.random.default_rng(2).standard_normal((3, 4))\n\n        columns = MultiIndex.from_tuples([("red", i) for i in gen])\n        df = DataFrame(data, index=list("def"), columns=columns)\n        df2 = pd.concat(\n            [\n                df,\n                DataFrame(\n                    "world",\n                    index=list("def"),\n                    columns=MultiIndex.from_tuples([("red", extra)]),\n                ),\n            ],\n            axis=1,\n        )\n\n        # check that the repr is good\n        # make sure that we have a correct sparsified repr\n        # e.g. only 1 header of read\n        assert str(df2).splitlines()[0].split() == ["red"]\n\n        # GH 8017\n        # sorting fails after columns added\n\n        # construct single-dtype then sort\n        result = df.copy().sort_index(axis=1)\n        expected = df.iloc[:, [0, 2, 1, 3]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df2.sort_index(axis=1)\n        expected = df2.iloc[:, [0, 2, 1, 4, 3]]\n        tm.assert_frame_equal(result, expected)\n\n        # setitem then sort\n        result = df.copy()\n        result[("red", extra)] = "world"\n\n        result = result.sort_index(axis=1)\n        tm.assert_frame_equal(result, expected)\n\n    @pytest.mark.parametrize(\n        "categories",\n        [\n            pytest.param(["a", "b", "c"], id="str"),\n            pytest.param(\n                [pd.Interval(0, 1), pd.Interval(1, 2), pd.Interval(2, 3)],\n                id="pd.Interval",\n            ),\n        ],\n    )\n    def test_sort_index_with_categories(self, categories):\n        # GH#23452\n        df = DataFrame(\n            {"foo": range(len(categories))},\n            index=CategoricalIndex(\n                data=categories, categories=categories, ordered=True\n            ),\n        )\n        df.index = df.index.reorder_categories(df.index.categories[::-1])\n        result = df.sort_index()\n        expected = DataFrame(\n            {"foo": reversed(range(len(categories)))},\n            index=CategoricalIndex(\n                data=categories[::-1], categories=categories[::-1], ordered=True\n            ),\n        )\n        tm.assert_frame_equal(result, expected)\n\n    @pytest.mark.parametrize(\n        "ascending",\n        [\n            None,\n            [True, None],\n            [False, "True"],\n        ],\n    )\n    def test_sort_index_ascending_bad_value_raises(self, ascending):\n        # GH 39434\n        df = DataFrame(np.arange(64))\n        length = len(df.index)\n        df.index = [(i - length / 2) % length for i in range(length)]\n        match = \'For argument "ascending" expected type bool\'\n        with pytest.raises(ValueError, match=match):\n            df.sort_index(axis=0, ascending=ascending, na_position="first")\n\n    @pytest.mark.parametrize(\n        "ascending",\n        [(True, False), [True, False]],\n    )\n    def test_sort_index_ascending_tuple(self, ascending):\n        df = DataFrame(\n            {\n                "legs": [4, 2, 4, 2, 2],\n            },\n            index=MultiIndex.from_tuples(\n                [\n                    ("mammal", "dog"),\n                    ("bird", "duck"),\n                    ("mammal", "horse"),\n                    ("bird", "penguin"),\n                    ("mammal", "kangaroo"),\n                ],\n                names=["class", "animal"],\n            ),\n        )\n\n        # parameter `ascending`` is a tuple\n        result = df.sort_index(level=(0, 1), ascending=ascending)\n\n        expected = DataFrame(\n            {\n                "legs": [2, 2, 2, 4, 4],\n            },\n            index=MultiIndex.from_tuples(\n                [\n                    ("bird", "penguin"),\n                    ("bird", "duck"),\n                    ("mammal", "kangaroo"),\n                    ("mammal", "horse"),\n                    ("mammal", "dog"),\n                ],\n                names=["class", "animal"],\n            ),\n        )\n\n        tm.assert_frame_equal(result, expected)\n\n\nclass TestDataFrameSortIndexKey:\n    def test_sort_multi_index_key(self):\n        # GH 25775, testing that sorting by index works with a multi-index.\n        df = DataFrame(\n            {"a": [3, 1, 2], "b": [0, 0, 0], "c": [0, 1, 2], "d": list("abc")}\n        ).set_index(list("abc"))\n\n        result = df.sort_index(level=list("ac"), key=lambda x: x)\n\n        expected = DataFrame(\n            {"a": [1, 2, 3], "b": [0, 0, 0], "c": [1, 2, 0], "d": list("bca")}\n        ).set_index(list("abc"))\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(level=list("ac"), key=lambda x: -x)\n        expected = DataFrame(\n            {"a": [3, 2, 1], "b": [0, 0, 0], "c": [0, 2, 1], "d": list("acb")}\n        ).set_index(list("abc"))\n\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_key(self):  # issue 27237\n        df = DataFrame(np.arange(6, dtype="int64"), index=list("aaBBca"))\n\n        result = df.sort_index()\n        expected = df.iloc[[2, 3, 0, 1, 5, 4]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(key=lambda x: x.str.lower())\n        expected = df.iloc[[0, 1, 5, 2, 3, 4]]\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(key=lambda x: x.str.lower(), ascending=False)\n        expected = df.iloc[[4, 2, 3, 0, 1, 5]]\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_key_int(self):\n        df = DataFrame(np.arange(6, dtype="int64"), index=np.arange(6, dtype="int64"))\n\n        result = df.sort_index()\n        tm.assert_frame_equal(result, df)\n\n        result = df.sort_index(key=lambda x: -x)\n        expected = df.sort_index(ascending=False)\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(key=lambda x: 2 * x)\n        tm.assert_frame_equal(result, df)\n\n    def test_sort_multi_index_key_str(self):\n        # GH 25775, testing that sorting by index works with a multi-index.\n        df = DataFrame(\n            {"a": ["B", "a", "C"], "b": [0, 1, 0], "c": list("abc"), "d": [0, 1, 2]}\n        ).set_index(list("abc"))\n\n        result = df.sort_index(level="a", key=lambda x: x.str.lower())\n\n        expected = DataFrame(\n            {"a": ["a", "B", "C"], "b": [1, 0, 0], "c": list("bac"), "d": [1, 0, 2]}\n        ).set_index(list("abc"))\n        tm.assert_frame_equal(result, expected)\n\n        result = df.sort_index(\n            level=list("abc"),  # can refer to names\n            key=lambda x: x.str.lower() if x.name in ["a", "c"] else -x,\n        )\n\n        expected = DataFrame(\n            {"a": ["a", "B", "C"], "b": [1, 0, 0], "c": list("bac"), "d": [1, 0, 2]}\n        ).set_index(list("abc"))\n        tm.assert_frame_equal(result, expected)\n\n    def test_changes_length_raises(self):\n        df = DataFrame({"A": [1, 2, 3]})\n        with pytest.raises(ValueError, match="change the shape"):\n            df.sort_index(key=lambda x: x[:1])\n\n    def test_sort_index_multiindex_sparse_column(self):\n        # GH 29735, testing that sort_index on a multiindexed frame with sparse\n        # columns fills with 0.\n        expected = DataFrame(\n            {\n                i: pd.array([0.0, 0.0, 0.0, 0.0], dtype=pd.SparseDtype("float64", 0.0))\n                for i in range(4)\n            },\n            index=MultiIndex.from_product([[1, 2], [1, 2]]),\n        )\n\n        result = expected.sort_index(level=0)\n\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_na_position(self):\n        # GH#51612\n        df = DataFrame([1, 2], index=MultiIndex.from_tuples([(1, 1), (1, pd.NA)]))\n        expected = df.copy()\n        result = df.sort_index(level=[0, 1], na_position="last")\n        tm.assert_frame_equal(result, expected)\n\n    def test_sort_index_multiindex_sort_remaining(self, ascending):\n        # GH #24247\n        df = DataFrame(\n            {"A": [1, 2, 3, 4, 5], "B": [10, 20, 30, 40, 50]},\n            index=MultiIndex.from_tuples(\n                [("a", "x"), ("a", "y"), ("b", "x"), ("b", "y"), ("c", "x")]\n            ),\n        )\n\n        result = df.sort_index(level=1, sort_remaining=False, ascending=ascending)\n\n        if ascending:\n            expected = DataFrame(\n                {"A": [1, 3, 5, 2, 4], "B": [10, 30, 50, 20, 40]},\n                index=MultiIndex.from_tuples(\n                    [("a", "x"), ("b", "x"), ("c", "x"), ("a", "y"), ("b", "y")]\n                ),\n            )\n        else:\n            expected = DataFrame(\n                {"A": [2, 4, 1, 3, 5], "B": [20, 40, 10, 30, 50]},\n                index=MultiIndex.from_tuples(\n                    [("a", "y"), ("b", "y"), ("a", "x"), ("b", "x"), ("c", "x")]\n                ),\n            )\n\n        tm.assert_frame_equal(result, expected)\n\n\ndef test_sort_index_with_sliced_multiindex():\n    # GH 55379\n    mi = MultiIndex.from_tuples(\n        [\n            ("a", "10"),\n            ("a", "18"),\n            ("a", "25"),\n            ("b", "16"),\n            ("b", "26"),\n            ("a", "45"),\n            ("b", "28"),\n            ("a", "5"),\n            ("a", "50"),\n            ("a", "51"),\n            ("b", "4"),\n        ],\n        names=["group", "str"],\n    )\n\n    df = DataFrame({"x": range(len(mi))}, index=mi)\n    result = df.iloc[0:6].sort_index()\n\n    expected = DataFrame(\n        {"x": [0, 1, 2, 5, 3, 4]},\n        index=MultiIndex.from_tuples(\n            [\n                ("a", "10"),\n                ("a", "18"),\n                ("a", "25"),\n                ("a", "45"),\n                ("b", "16"),\n                ("b", "26"),\n            ],\n            names=["group", "str"],\n        ),\n    )\n    tm.assert_frame_equal(result, expected)\n\n\ndef test_axis_columns_ignore_index():\n    # GH 56478\n    df = DataFrame([[1, 2]], columns=["d", "c"])\n    result = df.sort_index(axis="columns", ignore_index=True)\n    expected = DataFrame([[2, 1]])\n    tm.assert_frame_equal(result, expected)\n\n\ndef test_axis_columns_ignore_index_ascending_false():\n    # GH 57293\n    df = DataFrame(\n        {\n            "b": [1.0, 3.0, np.nan],\n            "a": [1, 4, 3],\n            1: ["a", "b", "c"],\n            "e": [3, 1, 4],\n            "d": [1, 2, 8],\n        }\n    ).set_index(["b", "a", 1])\n    result = df.sort_index(axis="columns", ignore_index=True, ascending=False)\n    expected = df.copy()\n    expected.columns = RangeIndex(2)\n    tm.assert_frame_equal(result, expected)\n\n\ndef test_sort_index_stable_sort():\n    # GH 57151\n    df = DataFrame(\n        data=[\n            (Timestamp("2024-01-30 13:00:00"), 13.0),\n            (Timestamp("2024-01-30 13:00:00"), 13.1),\n            (Timestamp("2024-01-30 12:00:00"), 12.0),\n            (Timestamp("2024-01-30 12:00:00"), 12.1),\n        ],\n        columns=["dt", "value"],\n    ).set_index(["dt"])\n    result = df.sort_index(level="dt", kind="stable")\n    expected = DataFrame(\n        data=[\n            (Timestamp("2024-01-30 12:00:00"), 12.0),\n            (Timestamp("2024-01-30 12:00:00"), 12.1),\n            (Timestamp("2024-01-30 13:00:00"), 13.0),\n            (Timestamp("2024-01-30 13:00:00"), 13.1),\n        ],\n        columns=["dt", "value"],\n    ).set_index(["dt"])\n    tm.assert_frame_equal(result, expected)\n',
        }
